import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
const Navbar = () => {
    const { user, logout, isAdmin, isSeller } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    const getRoleBadge = (role) => {
        switch(role) {
            case 'admin': return '👑 Админ';
            case 'seller': return '🏪 Продавец';
            case 'user': return '👤 Пользователь';
            default: return '';
        }
    };

    return (
        <nav style={styles.nav}>
            <div style={styles.logo}>Магазин</div>
            <div style={styles.links}>
                {user ? (
                    <>
                        {/* ✅ Отображаем роль */}
                        <span style={styles.roleBadge}>{getRoleBadge(user.role)}</span>
                        <span style={styles.username}>👤 {user.username}</span>

                        {/* ✅ Кнопка управления пользователями (только админ) */}
                        {isAdmin && (
                            <Link to="/admin/users" style={styles.adminLink}>
                                👥 Пользователи
                            </Link>
                        )}

                        <button onClick={handleLogout} style={styles.button}>
                            Выйти
                        </button>
                    </>
                ) : (
                    <>
                        <Link to="/login" style={styles.link}>Войти</Link>
                        <Link to="/register" style={styles.link}>Регистрация</Link>
                    </>
                )}
            </div>
        </nav>
    );
};

const styles = {
    nav: {
        backgroundColor: '#fff',
        padding: '15px 0',
        boxShadow: '0 2px 10px rgba(0,0,0,0.05)',
        position: 'sticky',
        top: 0,
        zIndex: 1000,
    },
    container: {
        maxWidth: '1200px',
        margin: '0 auto',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        padding: '0 20px',
    },
    logo: { fontSize: '20px', fontWeight: '800', color: '#1a1a1a', textDecoration: 'none' },
    menu: { display: 'flex', alignItems: 'center', gap: '20px' },
    userInfo: { display: 'flex', alignItems: 'center', gap: '15px' },
    username: { fontWeight: '600', color: '#333' },
    roleBadge: {
        backgroundColor: '#f0f2f5',
        padding: '4px 8px',
        borderRadius: '8px',
        fontSize: '12px',
        color: '#666',
        textTransform: 'uppercase',
    },
    logoutBtn: {
        padding: '8px 16px',
        borderRadius: '10px',
        border: '1.5px solid #eee',
        backgroundColor: '#fff',
        cursor: 'pointer',
        fontWeight: '600',
        transition: '0.2s',
    },
    link: { textDecoration: 'none', color: '#666', fontWeight: '600' },
    registerBtn: {
        textDecoration: 'none',
        backgroundColor: '#007AFF',
        color: '#fff',
        padding: '8px 20px',
        borderRadius: '10px',
        fontWeight: '600',
    }
};

export default Navbar;
